#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000.0f

struct neighbor {
    char entry[REC_LENGTH];
    float dist;
};

// Helper to parse a 5-char float string quickly
static float parse_float5(const char *str) {
    float val = 0.0f;
    float frac = 0.0f;
    float sign = 1.0f;
    float divisor = 1.0f;
    int in_frac = 0;

    // We assume the string is exactly 5 chars like " 12.3" or "-1.23"
    for (int i = 0; i < 5; i++) {
        char c = str[i];
        if (c == '-') {
            sign = -1.0f;
        } else if (c == '.') {
            in_frac = 1;
            divisor = 10.0f;
        } else if (c >= '0' && c <= '9') {
            int digit = c - '0';
            if (!in_frac) {
                val = val * 10.0f + (float)digit;
            } else {
                frac += (float)digit / divisor;
                divisor *= 10.0f;
            }
        }
    }
    return sign * (val + frac);
}

__kernel void compute_distances(
    const char *elem_9,
    float *z,
    float target_lat,
    float target_long,
    int x_6)
{
    int i = get_global_id(0);
    if (i >= x_6) return;

    int base_pos = i * REC_LENGTH + LATITUDE_POS - 1;

    // Parse latitude (5 chars)
    float x_4 = parse_float5(elem_9 + base_pos);

    // Parse longitude (5 chars, offset by 5)
    float data_7 = parse_float5(elem_9 + base_pos + 5);

    float diff_lat = x_4 - target_lat;
    float diff_long = data_7 - target_long;

    z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
}

__kernel void update_neighbors(
    const char *elem_9,
    const float *z,
    struct neighbor *val_14,
    int x_6,
    int k)
{
    int i = get_global_id(0);
    if (i >= x_6) return;

    float current_dist = z[i];

    // Find the neighbor with the maximum distance (the candidate for replacement)
    float max_dist = -1.0f;
    int max_idx = 0;

    for (int j = 0; j < k; j++) {
        if (val_14[j].dist > max_dist) {
            max_dist = val_14[j].dist;
            max_idx = j;
        }
    }

    // If the current record is closer than the farthest neighbor, replace it
    if (current_dist < max_dist) {
        int src_base = i * REC_LENGTH;
        // Copy entry string manually to avoid strcpy dependency
        for (int c = 0; c < REC_LENGTH - 1; c++) {
            val_14[max_idx].entry[c] = elem_9[src_base + c];
        }
        val_14[max_idx].entry[REC_LENGTH - 1] = '\0';
        val_14[max_idx].dist = current_dist;
    }
}
